import { useState } from "react";
import { motion } from "framer-motion";
import { design } from "../../design/authDesign";

const AdminLogin = () => {
  const [form, setForm] = useState({
    email: "",
    password: "",
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      const response = await fetch(
        "http://localhost:5000/api/auth/login",
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify(form),
        }
      );

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || "Login failed");
      }

      // Save token
      localStorage.setItem("adminInfo", JSON.stringify(data));

      console.log("Login Success:", data);

      // redirect later
      // navigate("/admin/dashboard")

    } catch (err) {
      setError(err.message);
    }

    setLoading(false);
  };

  return (
    <motion.div
      {...design.animation.container}
      className={`${design.colors.background} ${design.layout.container}`}
    >
      <motion.div
        {...design.animation.card}
        className={`${design.colors.card} ${design.layout.card}`}
      >
        {/* Title */}
        <div className="text-center mb-8">
          <h2 className={`text-3xl font-bold ${design.colors.title}`}>
            Admin Login
          </h2>
          <p className={`text-sm mt-2 ${design.colors.subtitle}`}>
            Enter your credentials to access dashboard
          </p>
        </div>

        {/* Error Message */}
        {error && (
          <div className="bg-red-500/10 text-red-500 text-sm p-3 rounded mb-4">
            {error}
          </div>
        )}

        {/* Form */}
        <form onSubmit={handleSubmit} className="space-y-5">
          <input
            type="email"
            name="email"
            placeholder="Admin Email"
            value={form.email}
            onChange={handleChange}
            className={`${design.layout.input} ${design.colors.inputBg} ${design.colors.inputBorder} ${design.colors.inputText}`}
            required
          />

          <input
            type="password"
            name="password"
            placeholder="Password"
            value={form.password}
            onChange={handleChange}
            className={`${design.layout.input} ${design.colors.inputBg} ${design.colors.inputBorder} ${design.colors.inputText}`}
            required
          />

          <button
            type="submit"
            disabled={loading}
            className={`${design.layout.button} ${design.colors.button} ${design.colors.buttonHover} text-white`}
          >
            {loading ? "Logging in..." : "Sign In"}
          </button>
        </form>
      </motion.div>
    </motion.div>
  );
};

export default AdminLogin;
